function stripHtml(html) {
  return String(html || "")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

let totalMinutes = 0;

const cleanEntries = entries.map((entry) => {
  const attrs = entry.attributes || {};
  const minutes = attrs.time || 0;
