  return {
    id: entry.id,
    date: attrs.date,
    minutes,
    hours: Number((minutes / 60).toFixed(2)),
    note: stripHtml(attrs.note),
  };
});

const totalHours = Number((totalMinutes / 60).toFixed(2));
const amount = Number((totalHours * hourlyRate).toFixed(2));

const warnings = [];

if (entries.length === 0) {
  warnings.push("No time entries found for this period.");
}

if (body.meta?.total_pages > 1) {
