const item = $json;
const source = item.source || {};

function normalizeNewlines(value) {
  return String(value || '').replace(/\\r\\n/g, '\n').replace(/\\n/g, '\n').replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
}

function asArray(value) {
  if (Array.isArray(value)) return value.map(String).map((v) => v.trim()).filter(Boolean);
  if (value === undefined || value === null || value === '') return [];
  return [String(value).trim()].filter(Boolean);
}

const reviewStatus = item.review_status || 'manual_review';
const invoiceNumber = source.invoice_number;
const invoiceToken = `Invoice #${invoiceNumber}`;
let recommendedAction = item.recommended_action || (reviewStatus === 'accepted' ? 'request_approval' : 'needs_manual_review');
let confidence = ['high', 'medium', 'low'].includes(item.confidence) ? item.confidence : 'medium';
const detectedIssues = asArray(item.detected_issues);

if (!source.period_start || !source.period_end || source.amount === undefined || source.amount === null || !invoiceNumber) {
  recommendedAction = 'stop';
  confidence = 'low';
  detectedIssues.push('Essential invoice data is missing.');
}

if ((source.warnings || []).length > 0 || Number(source.entry_count || 0) === 0 || Number(source.total_hours || 0) === 0) {
  if (recommendedAction === 'request_approval') recommendedAction = 'needs_manual_review';
  if (confidence === 'high') confidence = 'medium';
}

if (reviewStatus !== 'accepted' && recommendedAction === 'request_approval') {
  recommendedAction = 'needs_manual_review';
}

const emailSubject = normalizeNewlines(item.accepted_email_subject || invoiceToken);
const emailBody = normalizeNewlines(item.accepted_email_body || item.draft_email?.email_body || '');
if (!emailSubject.includes(invoiceToken) || !emailBody.includes(invoiceToken)) {
  recommendedAction = recommendedAction === 'stop' ? 'stop' : 'needs_manual_review';
  detectedIssues.push('Final email is missing the exact invoice number.');
}

const uniqueIssues = [...new Set(detectedIssues)];
const issueText = uniqueIssues.length ? uniqueIssues.join('; ') : 'none';
const telegramMessage = `Guilherme, Invoice #${invoiceNumber} passed the two-agent draft review with status ${reviewStatus}. Period: ${source.period_start} to ${source.period_end}. Hours: ${source.total_hours}. Amount: ${source.currency} ${source.amount}. Confidence: ${confidence}. Issues: ${issueText}. Reply approve, reject, or edit.`;

return {
  json: {
    ...source,
    confidence,
    recommended_action: recommendedAction,
    summary: reviewStatus === 'accepted' ? 'Two-agent review accepted the client email for human approval.' : 'Two-agent review did not accept the client email automatically.',
    detected_issues: uniqueIssues,
    work_summary: [],
    telegram_message: telegramMessage,
    email_subject: emailSubject,
    email_body: emailBody,
    email_review: {
      status: reviewStatus,
      attempts_used: item.attempt,
      score: item.score,
      checks: item.checks || {},
      review_feedback: item.review_feedback || '',
      previous_drafts: item.previous_drafts || [],
    },
    email_to: item.email_to || item.recipient_policy?.allowed_emails || [],
    email_cc: item.email_cc || [],
    email_bcc: item.email_bcc || [],
  },
};

